class PFFAllocator:
    def __init__(self, processes, total_frames):
        self.processes = processes
        self.total_frames = total_frames
        self.min_frames = 4  # minimum frames per process
        self.max_fault_rate = 5  # max faults per 1000 memory accesses
        self.min_fault_rate = 1

    def allocate(self):
        # Allocate minimum frames first
        allocated = 0
        for p in self.processes:
            p.frames = self.min_frames
            allocated += self.min_frames

        # Distribute remaining based on fault rate
        remaining = self.total_frames - allocated
        total_faults = sum(p.page_faults for p in self.processes)

        if total_faults > 0:
            for p in self.processes:
                if p.page_faults > 0:
                    extra = int((p.page_faults / total_faults) * remaining)
                    p.frames += extra

        # Adjust based on fault frequency
        for p in self.processes:
            fault_rate = p.page_faults / p.memory_accesses * 1000

            if fault_rate > self.max_fault_rate:
                p.frames += 2  # Add more frames
            elif fault_rate < self.min_fault_rate and p.frames > self.min_frames:
                p.frames -= 1  # Remove frames

        return [p.frames for p in self.processes]

