typedef struct {
    int process_id;
    int size_kb;
    int allocated_frames;
} Process;

void fixedAllocation(Process processes[], int n, int total_frames) {
    int frames_per_process = total_frames / n;
    int remaining_frames = total_frames % n;

    for (int i = 0; i < n; i++) {
        processes[i].allocated_frames = frames_per_process;
    }

    // Distribute remaining frames arbitrarily (e.g., to first few processes)
    for (int i = 0; i < remaining_frames; i++) {
        processes[i].allocated_frames++;
    }
}

int main() {
    Process processes[3] = {
        {1, 200, 0},
        {2, 400, 0},
        {3, 600, 0}
    };

    int total_frames = 100;
    fixedAllocation(processes, 3, total_frames);

    printf("Fixed Allocation Results:\n");
    for (int i = 0; i < 3; i++) {
        printf("Process %d: %d frames\n",
               processes[i].process_id,
               processes[i].allocated_frames);
    }
    return 0;
}

import java.util.*;

class Process {
    int id;
    int sizeKB;
    int priority; // 1 = highest priority
    int allocatedFrames;

    Process(int id, int sizeKB, int priority) {
        this.id = id;
        this.sizeKB = sizeKB;
        this.priority = priority;
    }
}

public class PriorityFrameAllocator {

    public static void allocateByPriority(List<Process> processes, int totalFrames) {
        // Sort by priority (higher priority first)
        processes.sort(Comparator.comparingInt(p -> p.priority).reversed());

        int totalSize = processes.stream()
            .mapToInt(p -> p.sizeKB).sum();

        // First pass: proportional based on size
        int[] tempAlloc = new int[processes.size()];
        int allocated = 0;

        for (int i = 0; i < processes.size(); i++) {
            double proportion = (double) processes.get(i).sizeKB / totalSize;
            tempAlloc[i] = (int) (proportion * totalFrames);
            allocated += tempAlloc[i];
        }

        // Bonus frames for high priority processes
        int bonusFrames = totalFrames - allocated;
        int bonusPerPriority = bonusFrames / processes.size();

        for (int i = 0; i < processes.size(); i++) {
            // Higher priority gets more bonus
            int priorityBonus = bonusPerPriority * (processes.size() - processes.get(i).priority + 1);
            processes.get(i).allocatedFrames = tempAlloc[i] + priorityBonus;
        }
    }

    public static void main(String[] args) {
        List<Process> processes = Arrays.asList(
            new Process(1, 200, 3),
            new Process(2, 400, 1),  // Highest priority
            new Process(3, 300, 2)
        );

        allocateByPriority(processes, 100);

        for (Process p : processes) {
            System.out.println("Process " + p.id +
                " (Priority " + p.priority + "): " +
                p.allocatedFrames + " frames");
        }
    }
}
